import{_ as a,o as i,c as e,ai as r}from"./chunks/framework.ampVZV4B.js";const u=JSON.parse('{"title":"02 云端部署：托管 API / 自建推理 / 混合方案","description":"","frontmatter":{},"headers":[],"relativePath":"ai/model-deploy/02-cloud-deploy.md","filePath":"ai/model-deploy/02-cloud-deploy.md"}'),o={name:"ai/model-deploy/02-cloud-deploy.md"};function t(n,l,s,d,h,_){return i(),e("div",null,[...l[0]||(l[0]=[r('<h1 id="_02-云端部署-托管-api-自建推理-混合方案" tabindex="-1">02 云端部署：托管 API / 自建推理 / 混合方案 <a class="header-anchor" href="#_02-云端部署-托管-api-自建推理-混合方案" aria-label="Permalink to “02 云端部署：托管 API / 自建推理 / 混合方案”">​</a></h1><blockquote><p>目标：根据预算与稳定性要求，选择“直接用云 API”还是“自建推理服务”，并能接入你的 Agent/MVP Server。</p></blockquote><h2 id="_1-云端适合什么场景" tabindex="-1">1）云端适合什么场景 <a class="header-anchor" href="#_1-云端适合什么场景" aria-label="Permalink to “1）云端适合什么场景”">​</a></h2><ul><li><strong>要强能力</strong>：更强推理、更长上下文、更好代码能力</li><li><strong>要稳定</strong>：不折腾本地环境，不受个人机器影响</li><li><strong>要并发</strong>：团队/小产品多人使用</li><li><strong>要快速上线</strong>：先跑通业务闭环，再考虑成本优化</li></ul><h2 id="_2-三种云端路线-怎么选" tabindex="-1">2）三种云端路线（怎么选） <a class="header-anchor" href="#_2-三种云端路线-怎么选" aria-label="Permalink to “2）三种云端路线（怎么选）”">​</a></h2><h3 id="_2-1-托管-api-最快" tabindex="-1">2.1 托管 API（最快） <a class="header-anchor" href="#_2-1-托管-api-最快" aria-label="Permalink to “2.1 托管 API（最快）”">​</a></h3><ul><li><strong>适合</strong>：你要最快把功能做出来（脚本/小工具/原型）</li><li><strong>优点</strong>：稳定、维护成本低、迭代快</li><li><strong>缺点</strong>：长期成本与合规/隐私要评估</li></ul><h3 id="_2-2-自建推理-gpu-实例-推理引擎" tabindex="-1">2.2 自建推理（GPU 实例 + 推理引擎） <a class="header-anchor" href="#_2-2-自建推理-gpu-实例-推理引擎" aria-label="Permalink to “2.2 自建推理（GPU 实例 + 推理引擎）”">​</a></h3><ul><li><strong>适合</strong>：你要“可控、可定制、可成本优化”，并有一定运维能力</li><li><strong>优点</strong>：模型/版本/日志更可控</li><li><strong>缺点</strong>：搭建与维护成本更高（监控、扩容、限流等）</li></ul><h3 id="_2-3-混合方案-推荐" tabindex="-1">2.3 混合方案（推荐） <a class="header-anchor" href="#_2-3-混合方案-推荐" aria-label="Permalink to “2.3 混合方案（推荐）”">​</a></h3><ul><li><strong>策略</strong>： <ul><li>日常/隐私：本地小模型</li><li>关键任务/高质量：云端强模型</li></ul></li><li><strong>收益</strong>： <ul><li>成本可控</li><li>质量可控</li><li>体验稳定</li></ul></li></ul><h2 id="_3-和你的工程怎么对接-建议架构" tabindex="-1">3）和你的工程怎么对接（建议架构） <a class="header-anchor" href="#_3-和你的工程怎么对接-建议架构" aria-label="Permalink to “3）和你的工程怎么对接（建议架构）”">​</a></h2><ul><li>你的应用（Agent/前端）不直接绑死某一家模型</li><li>中间加一层 <code>LLM Gateway</code>（可以先写在你的服务里）： <ul><li>统一请求格式</li><li>统一日志/限流/重试</li><li>可切换：本地推理 / 云端 API</li></ul></li></ul><h2 id="_4-最小验收" tabindex="-1">4）最小验收 <a class="header-anchor" href="#_4-最小验收" aria-label="Permalink to “4）最小验收”">​</a></h2><ul><li>你能用云端 API 做一次“面试题生成器”</li><li>并且把调用封装成一个函数/接口，后续可替换模型提供方</li></ul>',15)])])}const g=a(o,[["render",t]]);export{u as __pageData,g as default};
